class QueryBuilder<T> {

  private conditions: string[] = [];

  private selectFields: (keyof T)[] = [];

  private limitVal?: number;

  select<K extends keyof T>(...fields: K[]): QueryBuilder<Pick<T, K>> {

    this.selectFields = fields as any;

    return this as any;

  }

  where(condition: string): this {

    this.conditions.push(condition);

    return this;  // return this để chain

  }

  limit(n: number): this {

    this.limitVal = n;

    return this;

  }

  build(): string {

    const fields = this.selectFields.join(', ') || '*';

    const where  = this.conditions.length ? ' WHERE ' + this.conditions.join(' AND ') : '';

    const limit  = this.limitVal ? ' LIMIT ' + this.limitVal : '';

    return `SELECT ${fields}${where}${limit}`;

  }

  }

